package com.kalyani.car_rental_backend.emergency.controller;import com.kalyani.car_rental_backend.emergency.dto.EmergencyContactRequest;import com.kalyani.car_rental_backend.emergency.entity.EmergencyContact;import com.kalyani.car_rental_backend.emergency.repository.EmergencyContactRepository;import com.kalyani.car_rental_backend.exception.ResourceNotFoundException;import com.kalyani.car_rental_backend.response.ApiResponse;import com.kalyani.car_rental_backend.user.repository.UserRepository;import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController@RequestMapping("/emergency-contacts")public class EmergencyContactController{private final EmergencyContactRepository repo;private final UserRepository users;public EmergencyContactController(EmergencyContactRepository r,UserRepository u){repo=r;users=u;}@GetMapping public ResponseEntity<ApiResponse<List<Map<String,Object>>>>list(Authentication a){return ResponseEntity.ok(ApiResponse.success(repo.findByUserEmailIgnoreCase(a.getName()).stream().map(this::out).toList(),"Emergency contacts loaded"));}@PostMapping public ResponseEntity<ApiResponse<Map<String,Object>>>create(@Valid@RequestBody EmergencyContactRequest r,Authentication a){var u=users.findByEmailIgnoreCase(a.getName()).orElseThrow(()->new ResourceNotFoundException("User not found"));var e=new EmergencyContact();e.setUser(u);apply(e,r);return ResponseEntity.status(HttpStatus.CREATED).body(ApiResponse.success(out(repo.save(e)),"Emergency contact saved"));}@PutMapping("/{id}")public ResponseEntity<ApiResponse<Map<String,Object>>>update(@PathVariable Long id,@Valid@RequestBody EmergencyContactRequest r,Authentication a){var e=owned(id,a.getName());apply(e,r);return ResponseEntity.ok(ApiResponse.success(out(repo.save(e)),"Emergency contact updated"));}@DeleteMapping("/{id}")public ResponseEntity<ApiResponse<Void>>delete(@PathVariable Long id,Authentication a){repo.delete(owned(id,a.getName()));return ResponseEntity.ok(ApiResponse.success(null,"Emergency contact deleted"));}private EmergencyContact owned(Long id,String email){var e=repo.findById(id).orElseThrow(()->new ResourceNotFoundException("Contact not found"));if(!e.getUser().getEmail().equalsIgnoreCase(email))throw new IllegalArgumentException("You cannot access this contact");return e;}private void apply(EmergencyContact e,EmergencyContactRequest r){e.setName(r.name.trim());e.setPhone(r.phone);e.setRelationship(r.relationship);}private Map<String,Object>out(EmergencyContact e){return Map.of("id",e.getId(),"name",e.getName(),"phone",e.getPhone(),"relationship",e.getRelationship()==null?"":e.getRelationship());}}
